use serde_json::{json, Value};
fn execute(input: &Value) -> Value {
    let action = input["action"].as_str().unwrap_or("list");
    let new_item_str = input["new_item"].as_str().unwrap_or("");
    let items: Vec<String> = input["items"]
        .as_array()
        .map(|a| a.iter().filter_map(|v| v.as_str().map(|s| s.to_string())).collect())
        .unwrap_or_default();
    let (updated_items, clear_new) = match action {
        "add" => {
            if new_item_str.is_empty() {
                (items, false)
            } else {
                let mut out = items;
                out.push(new_item_str.to_string());
                (out, true)
            }
        }
        "remove" => {
            let idx = input["index"].as_u64().unwrap_or(u64::MAX) as usize;
            let out: Vec<String> = items.into_iter().enumerate()
                .filter(|(i, _)| *i != idx)
                .map(|(_, v)| v)
                .collect();
            (out, false)
        }
        _ => (items, false),
    };
    json!({
        "items": updated_items,
        "new_item": if clear_new { "" } else { new_item_str }
    })
}
